import React from 'react';
import BlogCardTiltWrapper from '../components/BlogCardTiltWrapper';
import BlogFilterBar from '../components/BlogFilterBar';
import { Link } from 'react-router-dom';
import { motion } from 'framer-motion';
import { Helmet } from 'react-helmet-async';
import { BlogPost, blogPosts } from '../data/blog';
import { calculateReadingTime } from '../utils/readingTime';

export default function Blog(): React.ReactElement {
  const [posts, setPosts] = React.useState<BlogPost[]>([]);
  const [filter, setFilter] = React.useState<string | null>(null);
  const [search, setSearch] = React.useState('');

  React.useEffect(() => {
    // Use mock data instead of Sanity fetch
    setPosts(blogPosts);
  }, []);

  const allTags = Array.from(new Set(posts.flatMap((post) => post.tags || [])));
  const filteredPosts = React.useMemo(() => {
    return posts.filter((post) => {
      const matchesTag = filter ? (post.tags || []).includes(filter) : true;
      const searchContent = (post.title + ' ' + (post.summary || '')).toLowerCase();
      const matchesSearch = search
        ? searchContent.includes(search.toLowerCase())
        : true;
      return matchesTag && matchesSearch;
    });
  }, [posts, filter, search]);

  return (
    <>
      <Helmet>
        <title>Blog | Aminul Islam Bhuiyan Amin</title>
        <meta
          name="description"
          content="Read articles and insights on AI, ML, and software by Aminul Islam Bhuiyan Amin."
        />
        <meta property="og:title" content="Blog | Aminul Islam Bhuiyan Amin" />
        <meta
          property="og:description"
          content="Read articles and insights on AI, ML, and software by Aminul Islam Bhuiyan Amin."
        />
        <meta property="og:image" content="https://aminul01-g.github.io/logo512.png" />
        <meta property="og:type" content="website" />
        <meta property="og:url" content="https://aminul01-g.github.io/blog" />
        <meta name="twitter:card" content="summary_large_image" />
        <meta name="twitter:title" content="Blog | Aminul Islam Bhuiyan Amin" />
        <meta
          name="twitter:description"
          content="Read articles and insights on AI, ML, and software by Aminul Islam Bhuiyan Amin."
        />
        <meta name="twitter:image" content="https://aminul01-g.github.io/logo512.png" />
        <link rel="canonical" href="https://aminul01-g.github.io/blog" />
        <script type="application/ld+json">
          {JSON.stringify({
            '@context': 'https://schema.org',
            '@type': 'Blog',
            name: "Aminul Islam Bhuiyan Amin's Blog",
            description:
              'Read articles and insights on AI, ML, and software by Aminul Islam Bhuiyan Amin.',
            url: 'https://aminul01-g.github.io/blog',
            author: {
              '@type': 'Person',
              name: 'Aminul Islam Bhuiyan Amin',
              url: 'https://aminul01-g.github.io',
            },
            publisher: {
              '@type': 'Person',
              name: 'Aminul Islam Bhuiyan Amin',
            },
            blogPost: filteredPosts.map((post) => ({
              '@type': 'BlogPosting',
              headline: post.title,
              description: post.summary,
              datePublished: post.date,
              author: {
                '@type': 'Person',
                name: 'Aminul Islam Bhuiyan Amin',
              },
              url: `https://aminul01-g.github.io/blog/${post.slug}`,
            })),
          })}
        </script>
        {/* BreadcrumbList structured data in a separate script tag */}
        <script type="application/ld+json">
          {JSON.stringify({
            '@context': 'https://schema.org',
            '@type': 'BreadcrumbList',
            itemListElement: [
              {
                '@type': 'ListItem',
                position: 1,
                name: 'Home',
                item: 'https://aminul01-g.github.io/',
              },
              {
                '@type': 'ListItem',
                position: 2,
                name: 'Blog',
                item: 'https://aminul01-g.github.io/blog',
              },
            ],
          })}
        </script>
      </Helmet>
      <motion.section
        id="blog"
        className="relative max-w-5xl mx-auto p-8 GlassCard rounded-3xl animate-fadeInUp transition-all duration-300 mb-16 overflow-hidden mt-8"
        initial={{ opacity: 0, y: 40 }}
        whileInView={{ opacity: 1, y: 0 }}
        viewport={{ once: true, amount: 0.3 }}
        transition={{ duration: 0.7 }}
      >
        <h2 className="text-3xl font-bold text-center mb-2 bg-clip-text text-transparent bg-gradient-to-r from-[#4F46E5] to-[#7C3AED] relative z-10">
          Blog
        </h2>
        <p className="text-center text-[var(--theme-text-primary)] text-opacity-[0.50] mb-8 max-w-2xl mx-auto relative z-10">
          Insights, tutorials, and stories from my journey in tech, AI, and creative coding. Explore
          my thoughts, discoveries, and lessons learned along the way.
        </p>
        <BlogFilterBar
          tags={allTags}
          onFilter={setFilter}
          onSearch={setSearch}
          activeTag={filter}
        />
        <div className="grid gap-8 md:grid-cols-2 relative z-10">
          {filteredPosts.length === 0 ? (
            <div className="col-span-full text-center text-[var(--theme-text-primary)] text-opacity-[0.40] py-12 flex flex-col items-center">
              <svg
                className="w-16 h-16 text-[var(--theme-text-primary)] text-opacity-70 mb-4 opacity-50"
                fill="none"
                stroke="currentColor"
                viewBox="0 0 24 24"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth="1.5"
                  d="M19 20H5a2 2 0 01-2-2V6a2 2 0 012-2h10a2 2 0 012 2v1m2 13a2 2 0 01-2-2V7m2 13a2 2 0 002-2V9a2 2 0 00-2-2h-2m-4-3H9M7 16h6M7 8h6v4H7V8z"
                />
              </svg>
              <p className="text-xl font-semibold mb-2">No blog posts found</p>
              <p className="text-sm max-w-md">
                New articles and insights will be published here soon. Stay tuned!
              </p>
            </div>
          ) : (
            filteredPosts.map((post: BlogPost, i: number) => (
              <BlogCardTiltWrapper key={post.slug}>
                <motion.div
                  className="GlassCard rounded-2xl p-6 flex flex-col items-start transition-all duration-300 hover:scale-[1.03] group focus-within:ring-2 focus-within:ring-purple-500/40"
                  initial={{ opacity: 0, y: 24 }}
                  whileInView={{ opacity: 1, y: 0 }}
                  transition={{ duration: 0.12, delay: i * 0.06 }}
                  tabIndex={0}
                  aria-label={`Blog post: ${post.title}`}
                >
                  <Link
                    to={`/blog/${post.slug}`}
                    className="block w-full focus:outline-none focus:ring-2 focus:ring-primary rounded-lg transition-all duration-200 group-hover:scale-[1.02]"
                    style={{ minHeight: 64 }}
                    aria-label={`Read blog post: ${post.title}`}
                  >
                    <div className="flex items-center gap-3 mb-2">
                      <svg
                        className="w-6 h-6 text-primary/80 dark:text-primary/80 group-hover:scale-110 transition-transform"
                        fill="none"
                        stroke="currentColor"
                        strokeWidth="2"
                        viewBox="0 0 24 24"
                        aria-hidden="true"
                      >
                        <path
                          strokeLinecap="round"
                          strokeLinejoin="round"
                          d="M19 21H5a2 2 0 01-2-2V7a2 2 0 012-2h5l2-2h5a2 2 0 012 2v12a2 2 0 01-2 2z"
                        />
                      </svg>
                      <h3 className="text-xl font-semibold text-primary mb-0 dark:text-primary group-hover:underline">
                        {post.title}
                      </h3>
                    </div>
                    <div className="flex items-center gap-3 text-sm text-[var(--theme-text-primary)] text-opacity-[0.40] mb-2">
                      <span>{post.date}</span>
                      <span>•</span>
                      <span>{calculateReadingTime(post.body)}</span>
                    </div>
                    <div className="flex flex-wrap gap-2 mb-2">
                      {(post.tags || []).map((tag) => (
                        <span
                          key={tag}
                          className="bg-white/[0.06] text-[#8b5cf6] text-xs px-2 py-1 rounded"
                        >
                          #{tag}
                        </span>
                      ))}
                    </div>
                    <p className="text-[var(--theme-text-primary)] text-opacity-[0.60]">{post.summary}</p>
                  </Link>
                </motion.div>
              </BlogCardTiltWrapper>
            ))
          )}
        </div>
        {/* Floating Contact Button - removed, now handled globally */}
      </motion.section>
    </>
  );
}
